/**
 * Order pricing module.
 *
 * Computes the total price of an order: item subtotal, discounts, VAT, and
 * currency-aware rounding. The public surface is `computePrice`, the
 * `PricingFacade`, and the option/type exports; everything else is internal
 * machinery.
 */

export interface OrderItem {
  name: string;
  unitPrice: number;
  quantity: number;
}

export type Currency = "GBP" | "EUR" | "USD";

export interface Order {
  items: OrderItem[];
  currency: Currency;
  loyaltyMember: boolean;
}

// Currency-tagged amount. Arithmetic returns new values carrying the tag through.
class MoneyValue {
  constructor(
    readonly amount: number,
    readonly currency: Currency,
  ) {}

  plus(other: MoneyValue): MoneyValue {
    if (other.currency !== this.currency) {
      throw new Error("cannot add across currencies without conversion");
    }
    return new MoneyValue(this.amount + other.amount, this.currency);
  }

  times(factor: number): MoneyValue {
    return new MoneyValue(this.amount * factor, this.currency);
  }

  withAmount(amount: number): MoneyValue {
    return new MoneyValue(amount, this.currency);
  }
}

// Discount strategies: bulk (10+ items, 10% off), multi-line (3+ distinct products, 2% off), loyalty (5% off)
type DiscountFn = (order: Order, subtotal: number) => number | null;

const bulkDiscount: DiscountFn = (order, subtotal) => {
  const totalQty = order.items.reduce((sum, item) => sum + item.quantity, 0);
  return totalQty >= 10 ? subtotal * 0.9 : null;
};

const multiLineDiscount: DiscountFn = (order, subtotal) => {
  const distinctNames = new Set(order.items.map(item => item.name));
  return distinctNames.size >= 3 ? subtotal * 0.98 : null;
};

const loyaltyDiscount: DiscountFn = (order, subtotal) => {
  return order.loyaltyMember ? subtotal * 0.95 : null;
};

// Application order matters: bulk, then multi-line, then loyalty.
const DEFAULT_DISCOUNTS: DiscountFn[] = [bulkDiscount, multiLineDiscount, loyaltyDiscount];

// ---------------------------------------------------------------------------
// Pricing options
// ---------------------------------------------------------------------------

export interface PricingHooks {
  beforeStage?(stageName: string): void;
  afterStage?(stageName: string, runningTotal: number): void;
}

export interface PricingOptions {
  vatRate?: number;
  /** Only half-up rounding is implemented; the enum anticipates bankers'. */
  roundingMode?: "half-up";
  /** Reserved for localised price formatting. */
  locale?: string;
  /** Observability hooks invoked around every pipeline stage. */
  hooks?: PricingHooks;
}

const DEFAULT_PRICING_OPTIONS: Required<Omit<PricingOptions, "hooks">> = {
  vatRate: 0.2,
  roundingMode: "half-up",
  locale: "en-GB",
};

function resolveOptions(
  options?: PricingOptions,
): Required<Omit<PricingOptions, "hooks">> & { hooks: PricingHooks } {
  return {
    ...DEFAULT_PRICING_OPTIONS,
    ...(options ?? {}),
    hooks: options?.hooks ?? {},
  };
}

// All currencies round to 2 decimal places (cents/pence)
function roundToTwoDp(value: number): number {
  return Math.round(value * 100) / 100;
}

// Pricing pipeline
interface PricingContext {
  readonly order: Order;
  readonly options: ReturnType<typeof resolveOptions>;
  running: MoneyValue;
}

function computeSubtotal(order: Order): MoneyValue {
  let total = new MoneyValue(0, order.currency);
  for (const item of order.items) {
    const lineTotal = item.unitPrice * item.quantity;
    total = total.plus(new MoneyValue(lineTotal, order.currency));
  }
  return total;
}

function applyDiscounts(order: Order, subtotal: number): number {
  let result = subtotal;
  for (const discount of DEFAULT_DISCOUNTS) {
    const adjusted = discount(order, result);
    if (adjusted !== null) {
      result = adjusted;
    }
  }
  return result;
}

function runPricingPipeline(order: Order, options: ReturnType<typeof resolveOptions>): number {
  let running = computeSubtotal(order);

  if (options.hooks.beforeStage) options.hooks.beforeStage("discount");
  running = running.withAmount(applyDiscounts(order, running.amount));
  if (options.hooks.afterStage) options.hooks.afterStage("discount", running.amount);

  if (options.hooks.beforeStage) options.hooks.beforeStage("tax");
  running = running.times(1 + options.vatRate);
  if (options.hooks.afterStage) options.hooks.afterStage("tax", running.amount);

  if (options.hooks.beforeStage) options.hooks.beforeStage("rounding");
  running = running.withAmount(roundToTwoDp(running.amount));
  if (options.hooks.afterStage) options.hooks.afterStage("rounding", running.amount);

  return running.amount;
}

// Facade
export class PricingFacade {
  private readonly options: ReturnType<typeof resolveOptions>;

  constructor(options?: PricingOptions) {
    this.options = resolveOptions(options);
  }

  price(order: Order): number {
    return runPricingPipeline(order, this.options);
  }
}

export function computePrice(order: Order, options?: PricingOptions): number {
  return new PricingFacade(options).price(order);
}

